#include <stdio.h>
#include <stdlib.h>
int main() {
    long long T, N;
    if (scanf("%lld", &T) != 1) return 0;
    while (T--) {
        if (scanf("%lld", &N) != 1) break;
        long long sum = 3LL * N * (N + 1) / 2;
        printf("%lld\n", sum);
    }
    return 0;
}

